  const p = project;
  const discipline_colors = { Architecture:"#D03B2A", Structure:"#8B6E52", MEPF:"#1C1410", "Parametric Modelling":"#D03B2A", "Civil 3D":"#8B6E52", Visualisation:"#1C1410" };

