/* ── PROJECT CARD ── */
function ProjectCard({ project, onOpen }) {
  const [hover, bind] = useHover();
  const p = project;
  return (
    <div {...bind} style={{
      background:C.white, borderRadius:"1.5rem",
      border:`1px solid ${hover?C.red:C.lightWarm}`, overflow:"hidden",
      transition:"transform 0.3s,box-shadow 0.3s,border-color 0.3s",
      transform:hover?"translateY(-6px)":"translateY(0)",
      boxShadow:hover?"0 20px 60px rgba(28,20,16,0.14)":"none"
    }}>
      {/* Image area */}
      <div style={{ position:"relative", height:"200px", overflow:"hidden", background:C.dark }}>
        <img src={p.hero} alt={p.name} style={{
          position:"absolute", inset:0, width:"100%", height:"100%", objectFit:"cover",
          opacity:hover?1:0, transform:hover?"scale(1.05)":"scale(1.12)",
          transition:"opacity 0.45s ease,transform 0.55s ease"
        }} />
        <div style={{
          position:"absolute", inset:0,
          background:hover?"linear-gradient(to top,rgba(28,20,16,0.85) 0%,rgba(28,20,16,0.25) 60%,transparent 100%)":"rgba(0,0,0,0)",
          transition:"background 0.4s ease"
        }} />
        <div style={{ position:"absolute", right:"-2rem", bottom:"-2rem", width:"8rem", height:"8rem", borderRadius:"50%", background:"rgba(208,59,42,0.2)", opacity:hover?0:1, transition:"opacity 0.3s" }} />
        <div style={{ position:"absolute", bottom:0, left:0, padding:"1.4rem 1.8rem" }}>
          <div style={{ fontSize:"0.68rem", fontWeight:600, textTransform:"uppercase", letterSpacing:"0.14em", color:"rgba(253,252,249,0.55)", marginBottom:"0.5rem" }}>Project {p.num} · {p.type}</div>
          <div style={{ fontFamily:"'DM Serif Display',serif", fontSize:"1.2rem", color:C.white, lineHeight:1.2, marginBottom:"0.3rem" }}>{p.name}</div>
          <div style={{ fontSize:"0.68rem", fontWeight:600, textTransform:"uppercase", letterSpacing:"0.1em", color:C.red }}>{p.subtitle.split(" — ")[0]}</div>
        </div>
        {/* Preview button */}
        <button onClick={() => onOpen(p)} style={{
          position:"absolute", top:"1rem", right:"1rem",
          background:"rgba(253,252,249,0.15)", backdropFilter:"blur(8px)",
          border:"1px solid rgba(253,252,249,0.3)", borderRadius:"2rem",
          padding:"0.35rem 1rem", fontSize:"0.7rem", fontWeight:600,
          letterSpacing:"0.08em", textTransform:"uppercase", color:C.white,
          cursor:"pointer", opacity:hover?1:0,
          transform:hover?"translateY(0)":"translateY(-8px)",
          transition:"opacity 0.3s,transform 0.3s,background 0.2s"
        }}
        onMouseEnter={e => e.currentTarget.style.background = C.red}
        onMouseLeave={e => e.currentTarget.style.background = "rgba(253,252,249,0.15)"}
        >View Project ↗</button>
      </div>
      {/* Card body */}
      <div style={{ padding:"1.4rem 1.8rem 1.8rem" }}>
        <div style={{ display:"flex", flexDirection:"column", gap:"0.55rem" }}>
          {p.meta.slice(0,3).map(({k,v}) => (
            <div key={k} style={{ display:"flex", justifyContent:"space-between", alignItems:"baseline", fontSize:"0.8rem" }}>
              <span style={{ color:C.warm }}>{k}</span>
              <span style={{ color:C.dark, fontWeight:500, textAlign:"right", maxWidth:"55%" }}>{v}</span>
            </div>
          ))}
        </div>
        <div style={{ height:"1px", background:C.lightWarm, margin:"1rem 0" }} />
        <div style={{ display:"flex", flexWrap:"wrap", gap:"0.4rem" }}>
          {p.disciplines.map(d => <span key={d} style={{ fontSize:"0.68rem", fontWeight:500, padding:"0.25rem 0.6rem", borderRadius:"2rem", background:"rgba(208,59,42,0.08)", color:C.red }}>{d}</span>)}
        </div>
      </div>
    </div>
  );
}

