/* ══════════════════════════════════════════
   ROOT
══════════════════════════════════════════ */
export default function Portfolio() {
  const [activeSection, setActiveSection] = useState("home");
  const [openProject, setOpenProject] = useState(null);

  useEffect(() => {
    const sections = document.querySelectorAll("section[id]");
    const obs = new IntersectionObserver(
      entries => { entries.forEach(e => { if (e.isIntersecting) setActiveSection(e.target.id); }); },
      { threshold: 0.4 }
    );
    sections.forEach(s => obs.observe(s));
    return () => obs.disconnect();
  }, []);

  // Close on Escape key
  useEffect(() => {
    const handler = e => { if (e.key === "Escape") setOpenProject(null); };
    window.addEventListener("keydown", handler);
    return () => window.removeEventListener("keydown", handler);
  }, []);

  return (
    <>
      <style>{STYLES}</style>
      <div style={{ fontFamily:"'DM Sans',sans-serif", background:C.cream, color:C.dark, minHeight:"100vh" }}>
        <Nav active={activeSection} />
        <Hero />
        <About />
        <Skills />
        <Experience />
        <Projects onOpenProject={setOpenProject} />
        <Education />
        <Contact />
        <Footer />
        {openProject && <ProjectPage project={openProject} onClose={() => setOpenProject(null)} />}
      </div>
    </>
  );
}
